def _log(msg: str) -> None:
    sys.stderr.write('uc_recommender_deep_scan: ' + msg + '\n')
    sys.stderr.flush()


def _read_input_xml() -> Dict[str, Any]:
    raw = sys.stdin.read()
    if not raw.strip():
        return {}
    try:
        root = ET.fromstring(raw)
    except ET.ParseError as err:
        _log('failed to parse input XML: ' + str(err))
        return {}
